import type { MouseEvent } from 'react';

/** Desktop — Ctrl + left-click opens row action menu. */
export function isReportGridMenuClickTrigger(event: Pick<MouseEvent, 'ctrlKey' | 'button'>): boolean {
  return event.ctrlKey && event.button === 0;
}

export type ReportGridPointerPoint = Pick<MouseEvent, 'clientX' | 'clientY'>;
