import React, { useCallback, useMemo, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import {
  addToast,
  type ErpListRowEditHintState,
  type ErpListTableConfig,
  useViewMobileLayout,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import type { LedgerEntryDto } from '../../services/kt/models';
import { isRowEditHintDismissed } from '../../utils/erpListRowEditHintDismiss';
import { reportGridRowHintDismissStorageKey } from '../../utils/reportGridRowMenuHint';
import { formatDateLocal, formatVnd } from '../../utils/formatters';
import { openWorkspaceTab } from '../../utils/openWorkspaceTab';
import { resolveDocumentViewPath } from '../../utils/reportDocumentDrillDown';
import erp from '../../styles/erpPage.module.css';
import {
  ReportRowActionMenu,
  ReportSourceDocumentSlideout,
  type ReportRowMenuAction,
} from '../report';
import { exportLedgerRowsToExcel, formatLedgerExportFileName } from './exportLedgerExcel';
import { isReportGridMenuClickTrigger } from './reportGridMenuTrigger';
import { ReportGridRowHintLayer } from './ReportGridRowHintLayer';
import { useReportGridRowLongPress } from './useReportGridRowLongPress';
import rowStyles from './LedgerReportGrid.module.css';

export type LedgerReportGridLabels = {
  colDate: string;
  colVoucher: string;
  colDescription: string;
  colDebit: string;
  colCredit: string;
  colBalance?: string;
  rowMenuViewDocument: string;
  rowMenuViewReport: string;
  rowMenuPrint: string;
  rowMenuExport: string;
  rowMenuChart: string;
  slideoutTitle: string;
  slideoutClose: string;
  slideoutOpenFull: string;
  slideoutLoadError: string;
  chartComingSoon: string;
  exportSuccess: string;
  exportError: string;
  rowMenuHint: string;
  rowMenuHintTouch: string;
};

export type LedgerReportGridProps = {
  items: LedgerEntryDto[];
  labels: LedgerReportGridLabels;
  testIdPrefix: string;
  exportAccountCode: string;
  showBalance?: boolean;
  reportTitle?: string;
  onRefresh: () => void;
  tableConfig?: Partial<ErpListTableConfig>;
  /** Parity `getRowEditBlockedMessage` — hint copy on row click. */
  getRowMenuHintMessage?: (row: LedgerEntryDto) => string | undefined;
  /** localStorage key for "Tôi đã hiểu" — default `${testIdPrefix}-row-menu-hint-understood`. Pass `null` to disable. */
  rowMenuHintDismissStorageKey?: string | null;
};

export const LedgerReportGrid: React.FC<LedgerReportGridProps> = ({
  items,
  labels,
  testIdPrefix,
  exportAccountCode,
  showBalance = true,
  reportTitle,
  onRefresh,
  tableConfig,
  getRowMenuHintMessage: getRowMenuHintMessageProp,
  rowMenuHintDismissStorageKey: rowMenuHintDismissStorageKeyProp,
}) => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const location = useLocation();
  const viewMobile = useViewMobileLayout();
  const [menu, setMenu] = useState<{ x: number; y: number; row: LedgerEntryDto } | null>(null);
  const [slideout, setSlideout] = useState<LedgerEntryDto | null>(null);
  const [rowMenuHint, setRowMenuHint] = useState<ErpListRowEditHintState | null>(null);

  const defaultHintMessage = viewMobile ? labels.rowMenuHintTouch : labels.rowMenuHint;
  const getRowMenuHintMessage = useCallback(
    (row: LedgerEntryDto) => {
      if (getRowMenuHintMessageProp) return getRowMenuHintMessageProp(row);
      return defaultHintMessage;
    },
    [getRowMenuHintMessageProp, defaultHintMessage],
  );

  const hintDismissStorageKey = useMemo(() => {
    if (rowMenuHintDismissStorageKeyProp === null) return undefined;
    if (rowMenuHintDismissStorageKeyProp) return rowMenuHintDismissStorageKeyProp;
    return reportGridRowHintDismissStorageKey(testIdPrefix);
  }, [rowMenuHintDismissStorageKeyProp, testIdPrefix]);

  const menuLabels = {
    viewDocument: labels.rowMenuViewDocument,
    viewReport: labels.rowMenuViewReport,
    print: labels.rowMenuPrint,
    export: labels.rowMenuExport,
    chart: labels.rowMenuChart,
  };

  const openSlideoutForRow = useCallback((row: LedgerEntryDto) => {
    if (!row.canOpenSourceDocument || !row.sourceDocumentType || !row.sourceDocumentId) return;
    setSlideout(row);
  }, []);

  const openFullPageForRow = useCallback((row: LedgerEntryDto) => {
    const path = resolveDocumentViewPath(row.sourceDocumentType, row.sourceDocumentId);
    if (!path) return;
    openWorkspaceTab(
      {
        path,
        title: row.voucherCode || path,
        returnPath: location.pathname + location.search,
        returnTitle: reportTitle,
        documentType: row.sourceDocumentType ?? undefined,
      },
      navigate,
    );
    setSlideout(null);
  }, [navigate, location.pathname, location.search, reportTitle]);

  const handleMenuSelect = useCallback((action: ReportRowMenuAction) => {
    const row = menu?.row;
    if (!row) return;
    switch (action) {
      case 'viewDocument':
        openSlideoutForRow(row);
        break;
      case 'viewReport':
        onRefresh();
        break;
      case 'print':
        window.print();
        break;
      case 'export':
        try {
          exportLedgerRowsToExcel(items, formatLedgerExportFileName(exportAccountCode), {
            date: labels.colDate,
            voucher: labels.colVoucher,
            description: labels.colDescription,
            debit: labels.colDebit,
            credit: labels.colCredit,
            balance: labels.colBalance ?? 'Số dư',
          });
          dispatch(addToast({ message: labels.exportSuccess, type: 'success' }));
        } catch {
          dispatch(addToast({ message: labels.exportError, type: 'error' }));
        }
        break;
      case 'chart':
        dispatch(addToast({ message: labels.chartComingSoon, type: 'info' }));
        break;
      default:
        break;
    }
  }, [menu?.row, openSlideoutForRow, onRefresh, items, exportAccountCode, labels, dispatch]);

  const openRowMenu = useCallback(
    (x: number, y: number, row: LedgerEntryDto) => {
      setRowMenuHint(null);
      setMenu({ x, y, row });
    },
    [],
  );

  const longPress = useReportGridRowLongPress<LedgerEntryDto>({
    enabled: viewMobile,
    onLongPress: ({ row, x, y }) => openRowMenu(x, y, row),
  });

  const handleRowClick = useCallback(
    (e: React.MouseEvent, row: LedgerEntryDto) => {
      if (longPress.consumeClickAfterLongPress()) return;
      if (isReportGridMenuClickTrigger(e)) {
        openRowMenu(e.clientX, e.clientY, row);
        return;
      }
      const hintMessage = getRowMenuHintMessage(row);
      if (hintMessage) {
        if (!hintDismissStorageKey || !isRowEditHintDismissed(hintDismissStorageKey)) {
          setRowMenuHint({ x: e.clientX, y: e.clientY, message: hintMessage });
        }
      } else {
        setRowMenuHint(null);
      }
    },
    [longPress, openRowMenu, getRowMenuHintMessage, hintDismissStorageKey],
  );

  const handleRowContextMenu = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
  }, []);

  if (items.length === 0) return null;

  const tableWrapperClass = [
    erp.tableWrapper,
    tableConfig?.stickyHeader ? erp.tableWrapperStickyHead : '',
    tableConfig?.heightMode === 'fixed' && tableConfig.height ? erp.tableWrapperHeightFixed : '',
  ].filter(Boolean).join(' ');

  const tableWrapperStyle: React.CSSProperties | undefined =
    tableConfig?.heightMode === 'fixed' && tableConfig.height
      ? { maxHeight: tableConfig.height, height: tableConfig.height }
      : undefined;

  return (
    <>
      <div className={tableWrapperClass} style={tableWrapperStyle}>
        <table className={erp.table}>
          <thead>
            <tr>
              <th>{labels.colDate}</th>
              <th>{labels.colVoucher}</th>
              <th>{labels.colDescription}</th>
              <th className={erp.colRight}>{labels.colDebit}</th>
              <th className={erp.colRight}>{labels.colCredit}</th>
              {showBalance && labels.colBalance && (
                <th className={erp.colRight}>{labels.colBalance}</th>
              )}
            </tr>
          </thead>
          <tbody>
            {items.map((r, i) => (
              <tr
                key={`${r.voucherCode}-${r.entryDate}-${i}`}
                className={rowStyles.clickableRow}
                onClick={e => handleRowClick(e, r)}
                onContextMenu={handleRowContextMenu}
                onPointerDown={e => longPress.onPointerDown(e, r)}
                onPointerMove={longPress.onPointerMove}
                onPointerUp={longPress.onPointerUp}
                onPointerCancel={longPress.onPointerCancel}
                data-testid={`${testIdPrefix}-row-${i}`}
              >
                <td>{formatDateLocal(r.entryDate)}</td>
                <td><code>{r.voucherCode}</code></td>
                <td>{r.description}</td>
                <td className={erp.colRight}>{formatVnd(r.debitAmount)}</td>
                <td className={erp.colRight}>{formatVnd(r.creditAmount)}</td>
                {showBalance && labels.colBalance && (
                  <td className={erp.colRight}>{formatVnd(r.runningBalance)}</td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <ReportRowActionMenu
        open={menu != null}
        x={menu?.x ?? 0}
        y={menu?.y ?? 0}
        onClose={() => setMenu(null)}
        onSelect={handleMenuSelect}
        labels={menuLabels}
        canOpenDocument={menu?.row.canOpenSourceDocument === true}
        testIdPrefix={testIdPrefix}
      />

      <ReportSourceDocumentSlideout
        isOpen={slideout != null}
        onClose={() => setSlideout(null)}
        documentType={slideout?.sourceDocumentType ?? null}
        documentId={slideout?.sourceDocumentId ?? null}
        voucherCode={slideout?.voucherCode}
        title={labels.slideoutTitle}
        closeLabel={labels.slideoutClose}
        openFullLabel={labels.slideoutOpenFull}
        loadErrorLabel={labels.slideoutLoadError}
        onOpenFullPage={() => slideout && openFullPageForRow(slideout)}
        testIdPrefix={testIdPrefix}
      />

      <ReportGridRowHintLayer
        hint={rowMenuHint}
        dismissStorageKey={hintDismissStorageKey}
        onDismiss={() => setRowMenuHint(null)}
      />
    </>
  );
};
