import React, { useState } from 'react';
import {
  AnchoredDropdown,
  Button,
  ErpListToolbarButton,
  useDeviceContentSize,
  useViewMobileLayout,
} from '@linm-soft/common-components';
import erp from '../../styles/erpPage.module.css';

export type ReportListToolbarProps = {
  testIdPrefix: string;
  onRefresh: () => void;
  onChart: () => void;
  onPrint: () => void;
  onEditConfig?: () => void;
  canChart?: boolean;
  canPrint?: boolean;
  chartLabel: string;
};

/** Sticky toolbar — báo cáo ERP (Làm mới · Biểu đồ · In · Sửa config). */
export const ReportListToolbar: React.FC<ReportListToolbarProps> = ({
  testIdPrefix,
  onRefresh,
  onChart,
  onPrint,
  onEditConfig,
  canChart = false,
  canPrint = false,
  chartLabel,
}) => {
  const { isSmall } = useDeviceContentSize();
  const viewMobile = useViewMobileLayout();
  const mobileToolbar = isSmall || viewMobile;
  const [moreOpen, setMoreOpen] = useState(false);

  const refreshBtn = (
    <ErpListToolbarButton
      action="refresh"
      variant="secondary"
      size="sm"
      data-testid={`${testIdPrefix}-toolbar-refresh-btn`}
      onClick={onRefresh}
    />
  );

  const chartBtn = (
    <Button
      variant="secondary"
      size="sm"
      disabled={!canChart}
      data-testid={`${testIdPrefix}-toolbar-chart-btn`}
      onClick={onChart}
    >
      <i className="fas fa-chart-bar" aria-hidden /> {chartLabel}
    </Button>
  );

  const printBtn = (
    <ErpListToolbarButton
      action="print"
      variant="secondary"
      size="sm"
      disabled={!canPrint}
      data-testid={`${testIdPrefix}-toolbar-print-btn`}
      onClick={onPrint}
    />
  );

  const configBtn = onEditConfig ? (
    <ErpListToolbarButton
      action="editConfig"
      variant="secondary"
      size="sm"
      data-testid={`${testIdPrefix}-list-config-btn`}
      onClick={onEditConfig}
    />
  ) : null;

  const moreItems = (
    <>
      {chartBtn}
      {printBtn}
      {configBtn}
    </>
  );

  if (mobileToolbar) {
    return (
      <div className={erp.catalogToolbarSticky} data-testid={`${testIdPrefix}-report-toolbar`}>
        <div className={erp.catalogToolbarLine1}>
          <div className={erp.catalogToolbarLeft}>
            {refreshBtn}
            <AnchoredDropdown
              isOpen={moreOpen}
              onClose={() => setMoreOpen(false)}
              dropdownTestId={`${testIdPrefix}-toolbar-more-dropdown`}
              width={280}
              anchor={(
                <ErpListToolbarButton
                  action="more"
                  variant="secondary"
                  size="sm"
                  iconOnly
                  aria-label="Thêm thao tác"
                  data-testid={`${testIdPrefix}-toolbar-more-btn`}
                  onClick={() => setMoreOpen(v => !v)}
                />
              )}
            >
              <div className={erp.anchoredDropdownBody}>{moreItems}</div>
            </AnchoredDropdown>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={erp.catalogToolbarSticky} data-testid={`${testIdPrefix}-report-toolbar`}>
      <div className={erp.catalogToolbarLine1}>
        <div className={erp.catalogToolbarLeft}>
          {refreshBtn}
          {chartBtn}
          {printBtn}
          {configBtn}
        </div>
      </div>
    </div>
  );
};
